The goal is to print a single line using the C standard I/O library.

In C, printing to the terminal is done with **printf**, which is defined in the **stdio.h** header.

```
#include <stdio.h>

int main() {
    printf("Hello, World!\n");
    return 0;
}
```

The `\n` is the newline character, which moves the cursor to the next line.

Every C program starts executing in the **main function**, and returning `0` indicates successful execution.

Printing multiple lines in C simply requires multiple calls to **printf**.

```
#include <stdio.h>

int main() {
    printf("C programming\n");
    printf("is fun\n");
    return 0;
}
```

Each call prints one line. The newline character ensures the cursor moves to the next line after printing.

The `%d` format specifier prints integers.

```
#include <stdio.h>

int main() {
    printf("%d\n", 42);
    return 0;
}
```

`%d` tells `printf` to display an integer value.

To read numbers from input, C uses the **scanf** function.

```
#include <stdio.h>

int main() {
    int x;
    scanf("%d", &x);
    printf("%d\n", x);
    return 0;
}
```

`&x` gives scanf the memory location where the number should be stored.

We read two integers using `scanf` and add them.

```
#include <stdio.h>

int main() {
    int a,b;
    scanf("%d %d", &a, &b);
    printf("%d\n", a + b);
    return 0;
}
```

C performs integer addition with the `+` operator.

Subtraction works exactly like addition in C.

```
#include <stdio.h>

int main() {
    int a,b;
    scanf("%d %d", &a, &b);
    printf("%d\n", a - b);
}
```

The minus operator `-` subtracts values.

Multiplication uses the `*` operator.

```
#include <stdio.h>

int main(){
 int a,b;
 scanf("%d %d",&a,&b);
 printf("%d\n",a*b);
}
```

The result is printed using `%d`.

Integer division truncates decimals.

```
#include <stdio.h>

int main(){
 int a,b;
 scanf("%d %d",&a,&b);
 printf("%d\n",a/b);
}
```

Since variables are integers, the result will also be an integer.

Squaring a number means multiplying it by itself.

```
#include <stdio.h>

int main(){
 int x;
 scanf("%d",&x);
 printf("%d\n",x*x);
}
```

`x*x` computes the square.

The modulo operator `%` returns the remainder.

```
#include <stdio.h>

int main(){
 int x;
 scanf("%d",&x);

 if(x%2==0)
  printf("even\n");
 else
  printf("odd\n");
}
```

If the remainder when dividing by 2 is zero, the number is even.

Use a conditional comparison.

```
#include <stdio.h>

int main(){
 int a,b;
 scanf("%d %d",&a,&b);

 if(a>b)
  printf("%d\n",a);
 else
  printf("%d\n",b);
}
```

The `>` operator compares values.

A **for loop** is perfect for repeating tasks.

```
#include <stdio.h>

int main(){
 for(int i=1;i<=5;i++)
  printf("%d\n",i);
}
```

The loop runs while `i` is less than or equal to 5.

We extend the previous addition example.

```
#include <stdio.h>

int main(){
 int a,b,c;
 scanf("%d %d %d",&a,&b,&c);
 printf("%d\n",a+b+c);
}
```

The sum is computed with multiple `+` operations.

Absolute value means removing the negative sign.

```
#include <stdio.h>

int main(){
 int x;
 scanf("%d",&x);

 if(x<0)
  x=-x;

 printf("%d\n",x);
}
```

If the number is negative we multiply it by -1.

We accumulate the sum using a loop.

```
#include <stdio.h>

int main(){
 int n,sum=0;
 scanf("%d",&n);

 for(int i=1;i<=n;i++)
  sum+=i;

 printf("%d\n",sum);
}
```

`sum += i` adds each number to the total.

We read a string and count until the null terminator.

```
#include <stdio.h>
#include <string.h>

int main(){
 char s[100];
 scanf("%s",s);
 printf("%lu\n",strlen(s));
}
```

`strlen` returns the length of a string.

Simply swap the order in printf.

```
#include <stdio.h>

int main(){
 int a,b;
 scanf("%d %d",&a,&b);
 printf("%d %d\n",b,a);
}
```

We do not need to modify the variables.

Factorial multiplies numbers from 1 to n.

```
#include <stdio.h>

int main(){
 int n;
 long long f=1;
 scanf("%d",&n);

 for(int i=1;i<=n;i++)
  f*=i;

 printf("%lld\n",f);
}
```

`long long` avoids overflow for small factorials.

A loop prints numbers with spaces.

```
#include <stdio.h>

int main(){
 int n;
 scanf("%d",&n);

 for(int i=1;i<=n;i++)
  printf("%d ",i);

 printf("\n");
}
```

The trailing newline ensures consistent output.

Track the maximum value.

```
#include <stdio.h>

int main(){
 int a,b,c,m;
 scanf("%d %d %d",&a,&b,&c);

 m=a;
 if(b>m) m=b;
 if(c>m) m=c;

 printf("%d\n",m);
}
```

Each comparison updates the maximum.

We read numbers in a loop.

```
#include <stdio.h>

int main(){
 int n,x,sum=0;
 scanf("%d",&n);

 for(int i=0;i<n;i++){
  scanf("%d",&x);
  sum+=x;
 }

 printf("%d\n",sum);
}
```

Each input value is added to the running total.

Use the modulo operator.

```
#include <stdio.h>

int main(){
 int n,x,c=0;
 scanf("%d",&n);

 for(int i=0;i<n;i++){
  scanf("%d",&x);
  if(x%2==0) c++;
 }

 printf("%d\n",c);
}
```

Every even number increments the counter.

Repeatedly extract digits.

```
#include <stdio.h>

int main(){
 int n,r;
 scanf("%d",&n);

 while(n>0){
  r=n%10;
  printf("%d",r);
  n/=10;
 }
 printf("\n");
}
```

`%10` extracts the last digit.

Repeated multiplication computes powers.

```
#include <stdio.h>

int main(){
 int a,b;
 long long r=1;
 scanf("%d %d",&a,&b);

 for(int i=0;i<b;i++)
  r*=a;

 printf("%lld\n",r);
}
```

The loop multiplies `a` by itself `b` times.

Average equals sum divided by count.

```
#include <stdio.h>

int main(){
 int n,x,sum=0;
 scanf("%d",&n);

 for(int i=0;i<n;i++){
  scanf("%d",&x);
  sum+=x;
 }

 printf("%d\n",sum/n);
}
```

Since the output is integer average, integer division is correct.

A number is prime if it has no divisors besides 1 and itself.

```
#include <stdio.h>

int main(){
 int n,prime=1;
 scanf("%d",&n);

 if(n<2) prime=0;

 for(int i=2;i*i<=n;i++)
  if(n%i==0) prime=0;

 if(prime) printf("prime\n");
 else printf("not prime\n");
}
```

Checking up to `sqrt(n)` makes the algorithm efficient.

Use the Euclidean algorithm.

```
#include <stdio.h>

int main(){
 int a,b,t;
 scanf("%d %d",&a,&b);

 while(b!=0){
  t=b;
  b=a%b;
  a=t;
 }

 printf("%d\n",a);
}
```

The algorithm repeatedly replaces the pair `(a,b)` with `(b, a mod b)`.

Fibonacci numbers follow:

F(n) = F(n-1) + F(n-2)

```
#include <stdio.h>

int main(){
 int n;
 long long a=0,b=1,c;
 scanf("%d",&n);

 for(int i=2;i<=n;i++){
  c=a+b;
  a=b;
  b=c;
 }

 printf("%lld\n",b);
}
```

This iterative solution avoids recursion overhead.

Reverse the number and compare.

```
#include <stdio.h>

int main(){
 int n,t,r,rev=0;
 scanf("%d",&n);

 t=n;

 while(t>0){
  r=t%10;
  rev=rev*10+r;
  t/=10;
 }

 if(rev==n) printf("yes\n");
 else printf("no\n");
}
```

If the reversed number equals the original, it is a palindrome.

Repeated division counts digits.

```
#include <stdio.h>

int main(){
 int n,c=0;
 scanf("%d",&n);

 while(n!=0){
  n/=10;
  c++;
 }

 printf("%d\n",c);
}
```

Each division by 10 removes one digit.

We process digits from right to left.

```
#include <stdio.h>

int main(){
 int n,base=1,dec=0,r;
 scanf("%d",&n);

 while(n>0){
  r=n%10;
  dec+=r*base;
  base*=2;
  n/=10;
 }

 printf("%d\n",dec);
}
```

Each digit contributes a power of two.

Repeated division by two builds binary digits.

```
#include <stdio.h>

int main(){
 int n,bin[32],i=0;
 scanf("%d",&n);

 while(n>0){
  bin[i++]=n%2;
  n/=2;
 }

 for(int j=i-1;j>=0;j--)
  printf("%d",bin[j]);

 printf("\n");
}
```

Digits are generated in reverse order and then printed backward.

Bubble sort repeatedly swaps adjacent elements.

```
#include <stdio.h>

int main(){
 int n,a[100];
 scanf("%d",&n);

 for(int i=0;i<n;i++)
  scanf("%d",&a[i]);

 for(int i=0;i<n;i++)
  for(int j=0;j<n-1;j++)
   if(a[j]>a[j+1]){
    int t=a[j];
    a[j]=a[j+1];
    a[j+1]=t;
   }

 for(int i=0;i<n;i++)
  printf("%d ",a[i]);

 printf("\n");
}
```

Bubble sort is simple but not efficient for large arrays.

We store the matrix in a 2D array.

```
#include <stdio.h>

int main(){
 int a[2][2],sum=0;

 for(int i=0;i<2;i++)
  for(int j=0;j<2;j++){
   scanf("%d",&a[i][j]);
   sum+=a[i][j];
  }

 printf("%d\n",sum);
}
```

Each element contributes to the total sum.

We reverse the string by iterating backwards.

```
#include <stdio.h>
#include <string.h>

int main(){
 char s[100];
 scanf("%s",s);

 int n=strlen(s);

 for(int i=n-1;i>=0;i--)
  printf("%c",s[i]);

 printf("\n");
}
```

`strlen` determines the last index, and we print characters in reverse order.
